const inputData = items[0].json.output || items[0].json;
const docId = items[0].json.id || items[0].json.documentId;

let parsed;
if (typeof inputData === 'string') {
    try {
        parsed = JSON.parse(inputData);
    } catch(e) { 
        parsed = { content_markdown: inputData, doc_name: "Без названия" }; 
    }
} else {
    parsed = inputData;
}

const md = parsed.content_markdown || "";
const docName = parsed.doc_name || "Новый документ"; // Вот мы получили doc_name отдельно

const lines = md.split('\n');
let requests = [];
let currentIndex = 1; 

for (let line of lines) {
    let style = 'NORMAL_TEXT';
    let cleanText = line;

    if (line.startsWith('# ')) {
        style = 'HEADING_1';
        cleanText = line.replace('# ', '');
    } else if (line.startsWith('## ')) {
        style = 'HEADING_2';
        cleanText = line.replace('## ', '');
    }

    cleanText = cleanText.replace(/\*\*/g, '').trim();

    if (cleanText === "") {
        requests.push({ insertText: { location: { index: currentIndex }, text: "\n" } });
        currentIndex += 1;
        continue;
    }

    const fullText = cleanText + "\n";
    const length = fullText.length;

    requests.push({
        insertText: { location: { index: currentIndex }, text: fullText }
    });

    if (style !== 'NORMAL_TEXT') {
        requests.push({
            updateParagraphStyle: {
                range: { startIndex: currentIndex, endIndex: currentIndex + length },
                paragraphStyle: { namedStyleType: style },
                fields: 'namedStyleType'
            }
        });
    }
    currentIndex += length;
}

// Теперь узел выдает и название, и массив запросов, и ID
return { 
    documentId: docId, 
    doc_name: docName, 
    requests: requests 
};
